{
  "title": "फ्यू-शॉट उदाहरण",
  "group": "प्रॉम्प्ट संरचना",
  "options": [
    {
      "text": "अधिक उदाहरण हमेशा बेहतर परिणाम देते हैं"
    },
    {
      "text": "प्रॉम्प्ट में 3–5 उच्च-गुणवत्ता वाले, विविध उदाहरण"
    },
    {
      "text": "फ्यू-शॉट उदाहरण केवल वर्गीकरण कार्यों के लिए सहायक होते हैं"
    },
    {
      "text": "उदाहरण उपयोगकर्ता प्रश्न के बाद रखे जाने चाहिए, पहले नहीं"
    }
  ],
  "questionProse": [
    "अधिकांश उत्पादन उपयोग मामलों के लिए, इष्टतम फ्यू-शॉट उदाहरण रणनीति है:"
  ],
  "explanationProse": [
    "फ्यू-शॉट उदाहरण आउटपुट स्थिरता और प्रारूप पालन में नाटकीय रूप से सुधार करते हैं। अधिकांश कार्यों के लिए सबसे उपयुक्त संख्या **3–5 उच्च-गुणवत्ता वाले, विविध उदाहरण** है।\n\n    अधिक क्यों नहीं? प्रत्येक उदाहरण टोकन की लागत लेता है। 5–10 उदाहरणों के बाद, सीमांत लाभ घटता है जबकि टोकन लागत बढ़ती रहती है। अधिक उदाहरण मॉडल के अंतर्निहित पैटर्न को समझने के बजाय उदाहरणों पर ओवरफिट होने की संभावना भी बढ़ाते हैं।\n\n    विविधता क्यों महत्वपूर्ण है: यदि आपके सभी उदाहरण एक ही प्रकार के इनपुट हैं, तो मॉडल किनारे के मामलों पर अच्छी तरह से सामान्यीकरण नहीं करेगा। अपने सबसे महत्वपूर्ण विविधताओं को कवर करने वाले उदाहरण शामिल करें।\n\n    स्थान: उदाहरण उपयोगकर्ता प्रश्न से *पहले* रखे जाने चाहिए, सिस्टम प्रॉम्प्ट के भाग के रूप में या पूर्व-भरे वार्तालाप टर्न के रूप में — बाद में नहीं।"
  ]
}
